//.js 主函数 exec()
function exec(){
 var localName = quickerGetVar('text');  // 读取text变量值, (text 是动作里的变量)
 quickerSetVar('text', 'Hello, ' + localName ); //输出修改后的值到text变量中。
 return 0; //返回0表示成功。返回其他数字表示失败。
}
